// Get Gemini response
const geminiResponse = $input.first().json.content.parts[0].text;

// Clean markdown
const cleaned = geminiResponse
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Parse JSON
const result = JSON.parse(cleaned);

// Add timestamps
result.v2_memo.generated_at = new Date().toISOString();
result.changelog.generated_at = new Date().toISOString();

// Prepare v2 memo binary
const v2Binary = await this.helpers.prepareBinaryData(
  Buffer.from(JSON.stringify(result.v2_memo, null, 2)),
  'account_memo.json',
  'application/json'
);

// Prepare changelog binary
const changelogBinary = await this.helpers.prepareBinaryData(
  Buffer.from(JSON.stringify(result.changelog, null, 2)),
  'changelog.json',
  'application/json'
);

return {
  json: {
    v2_memo: result.v2_memo,
    changelog: result.changelog
  },
  binary: {
    v2_memo: v2Binary,
    changelog: changelogBinary
  }
};
